-- ============================================================================
-- RF-055 — pgTAP: authorization (D-028 separation of duties)
-- ============================================================================
-- open_shift: cashier/manager/restaurant_owner/org_owner may open; kitchen_staff/
-- accountant denied. close_shift: a cashier may close only their OWN shift;
-- manager+ may close on behalf; accountant/kitchen denied. reconcile_shift:
-- manager/restaurant_owner/org_owner only; cashier (incl. the counter)/accountant/
-- kitchen denied. Denied attempts are audited. A shift in another branch is rejected.
-- One device (da11) is cycled (terminal shifts free it); branch b2 covers cross-scope.
-- Fixtures inserted as the BYPASSRLS connection role.
-- ============================================================================
begin;
create extension if not exists pgtap with schema extensions;
set local search_path to extensions, public, pg_catalog;

select plan(20);

insert into organizations (id, name, slug, default_currency) values
  ('00000000-0000-0000-0000-0000000000a0', 'Org A', 'rf055z-a', 'USD');
insert into restaurants (id, organization_id, name) values
  ('00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-0000000000a0', 'Rest A1');
insert into branches (id, organization_id, restaurant_id, name) values
  ('00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', 'Branch A1'),
  ('00000000-0000-0000-0000-00000000a1b2', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', 'Branch A2');
