  ('00000000-0000-0000-0000-00000000fa11', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-00000000da11', 'active'),
  ('00000000-0000-0000-0000-00000000fb22', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b2', '00000000-0000-0000-0000-00000000db22', 'active');
insert into device_sessions (id, organization_id, restaurant_id, branch_id, device_id, device_pairing_id) values
  ('00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-00000000da11', '00000000-0000-0000-0000-00000000fa11'),
  ('00000000-0000-0000-0000-0000000005b2', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b2', '00000000-0000-0000-0000-00000000db22', '00000000-0000-0000-0000-00000000fb22');
insert into app_users (id, email) values
  ('00000000-0000-0000-0000-00000000ee01', 'rf055z-cashier1@example.test'),
  ('00000000-0000-0000-0000-00000000ee05', 'rf055z-cashier2@example.test'),
  ('00000000-0000-0000-0000-00000000ee02', 'rf055z-manager@example.test'),
  ('00000000-0000-0000-0000-00000000ee06', 'rf055z-rowner@example.test'),
  ('00000000-0000-0000-0000-00000000ee07', 'rf055z-oowner@example.test'),
  ('00000000-0000-0000-0000-00000000ee03', 'rf055z-accountant@example.test'),
  ('00000000-0000-0000-0000-00000000ee04', 'rf055z-kitchen@example.test');
insert into memberships (id, app_user_id, organization_id, restaurant_id, branch_id, role) values
  ('00000000-0000-0000-0000-00000000ab01', '00000000-0000-0000-0000-00000000ee01', '00000000-0000-0000-0000-0000000000a0', null, null, 'cashier'),
  ('00000000-0000-0000-0000-00000000ab05', '00000000-0000-0000-0000-00000000ee05', '00000000-0000-0000-0000-0000000000a0', null, null, 'cashier'),
  ('00000000-0000-0000-0000-00000000ab02', '00000000-0000-0000-0000-00000000ee02', '00000000-0000-0000-0000-0000000000a0', null, null, 'manager'),
  ('00000000-0000-0000-0000-00000000ab06', '00000000-0000-0000-0000-00000000ee06', '00000000-0000-0000-0000-0000000000a0', null, null, 'restaurant_owner'),
  ('00000000-0000-0000-0000-00000000ab07', '00000000-0000-0000-0000-00000000ee07', '00000000-0000-0000-0000-0000000000a0', null, null, 'org_owner'),
  ('00000000-0000-0000-0000-00000000ab03', '00000000-0000-0000-0000-00000000ee03', '00000000-0000-0000-0000-0000000000a0', null, null, 'accountant'),
  ('00000000-0000-0000-0000-00000000ab04', '00000000-0000-0000-0000-00000000ee04', '00000000-0000-0000-0000-0000000000a0', null, null, 'kitchen_staff');
insert into employee_profiles (id, organization_id, restaurant_id, branch_id, app_user_id, membership_id) values
  ('00000000-0000-0000-0000-0000000ef001', '00000000-0000-0000-0000-0000000000a0', null, null, '00000000-0000-0000-0000-00000000ee01', '00000000-0000-0000-0000-00000000ab01'),
  ('00000000-0000-0000-0000-0000000ef005', '00000000-0000-0000-0000-0000000000a0', null, null, '00000000-0000-0000-0000-00000000ee05', '00000000-0000-0000-0000-00000000ab05'),
  ('00000000-0000-0000-0000-0000000ef002', '00000000-0000-0000-0000-0000000000a0', null, null, '00000000-0000-0000-0000-00000000ee02', '00000000-0000-0000-0000-00000000ab02'),
  ('00000000-0000-0000-0000-0000000ef006', '00000000-0000-0000-0000-0000000000a0', null, null, '00000000-0000-0000-0000-00000000ee06', '00000000-0000-0000-0000-00000000ab06'),
  ('00000000-0000-0000-0000-0000000ef007', '00000000-0000-0000-0000-0000000000a0', null, null, '00000000-0000-0000-0000-00000000ee07', '00000000-0000-0000-0000-00000000ab07'),
  ('00000000-0000-0000-0000-0000000ef003', '00000000-0000-0000-0000-0000000000a0', null, null, '00000000-0000-0000-0000-00000000ee03', '00000000-0000-0000-0000-00000000ab03'),
  ('00000000-0000-0000-0000-0000000ef004', '00000000-0000-0000-0000-0000000000a0', null, null, '00000000-0000-0000-0000-00000000ee04', '00000000-0000-0000-0000-00000000ab04');
insert into pin_sessions (id, organization_id, restaurant_id, branch_id, device_session_id, employee_profile_id, resolved_membership_id, expires_at) values
  ('00000000-0000-0000-0000-00000000c5c1', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000ef001', '00000000-0000-0000-0000-00000000ab01', now() + interval '1 hour'),
  ('00000000-0000-0000-0000-00000000c5c2', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000ef005', '00000000-0000-0000-0000-00000000ab05', now() + interval '1 hour'),
  ('00000000-0000-0000-0000-00000000c5c3', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000ef002', '00000000-0000-0000-0000-00000000ab02', now() + interval '1 hour'),
  ('00000000-0000-0000-0000-00000000c5c4', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000ef006', '00000000-0000-0000-0000-00000000ab06', now() + interval '1 hour'),
  ('00000000-0000-0000-0000-00000000c5c5', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000ef007', '00000000-0000-0000-0000-00000000ab07', now() + interval '1 hour'),
  ('00000000-0000-0000-0000-00000000c5c6', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000ef003', '00000000-0000-0000-0000-00000000ab03', now() + interval '1 hour'),
  ('00000000-0000-0000-0000-00000000c5c7', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b1', '00000000-0000-0000-0000-0000000005a1', '00000000-0000-0000-0000-0000000ef004', '00000000-0000-0000-0000-00000000ab04', now() + interval '1 hour'),
  ('00000000-0000-0000-0000-00000000c5b2', '00000000-0000-0000-0000-0000000000a0', '00000000-0000-0000-0000-0000000000a1', '00000000-0000-0000-0000-00000000a1b2', '00000000-0000-0000-0000-0000000005b2', '00000000-0000-0000-0000-0000000ef002', '00000000-0000-0000-0000-00000000ab02', now() + interval '1 hour');

-- ===== open_shift: manager / restaurant_owner / org_owner can open =========== 1-6
-- (each cycle opens da11, closes, reconciles to terminal so the device frees up)
select is((app.open_shift('00000000-0000-0000-0000-00000000c5c3','00000000-0000-0000-0000-00000000a5f1','00000000-0000-0000-0000-00000000acd1','00000000-0000-0000-0000-00000000da11','o-m',0) ->> 'status'), 'open', 'manager may open a shift');
select app.close_shift('00000000-0000-0000-0000-00000000c5c3','00000000-0000-0000-0000-00000000a5f1','00000000-0000-0000-0000-00000000da11','c-m',0,null);
select is((app.reconcile_shift('00000000-0000-0000-0000-00000000c5c3','00000000-0000-0000-0000-00000000a5f1','00000000-0000-0000-0000-00000000da11','r-m',null) ->> 'status'), 'reconciled', 'manager may reconcile');
select is((app.open_shift('00000000-0000-0000-0000-00000000c5c4','00000000-0000-0000-0000-00000000a5f2','00000000-0000-0000-0000-00000000acd2','00000000-0000-0000-0000-00000000da11','o-r',0) ->> 'status'), 'open', 'restaurant_owner may open a shift');
select app.close_shift('00000000-0000-0000-0000-00000000c5c4','00000000-0000-0000-0000-00000000a5f2','00000000-0000-0000-0000-00000000da11','c-r',0,null);
select is((app.reconcile_shift('00000000-0000-0000-0000-00000000c5c4','00000000-0000-0000-0000-00000000a5f2','00000000-0000-0000-0000-00000000da11','r-r',null) ->> 'status'), 'reconciled', 'restaurant_owner may reconcile');
select is((app.open_shift('00000000-0000-0000-0000-00000000c5c5','00000000-0000-0000-0000-00000000a5f3','00000000-0000-0000-0000-00000000acd3','00000000-0000-0000-0000-00000000da11','o-o',0) ->> 'status'), 'open', 'org_owner may open a shift');
select app.close_shift('00000000-0000-0000-0000-00000000c5c5','00000000-0000-0000-0000-00000000a5f3','00000000-0000-0000-0000-00000000da11','c-o',0,null);
select is((app.reconcile_shift('00000000-0000-0000-0000-00000000c5c5','00000000-0000-0000-0000-00000000a5f3','00000000-0000-0000-0000-00000000da11','r-o',null) ->> 'status'), 'reconciled', 'org_owner may reconcile');

-- cashier1 opens da11 (covered in open test); used below for the close/reconcile gates
select app.open_shift('00000000-0000-0000-0000-00000000c5c1','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000acd4','00000000-0000-0000-0000-00000000da11','o-c1',0);

-- ===== open_shift: kitchen_staff / accountant denied ========================= 7-8
select is(app.open_shift('00000000-0000-0000-0000-00000000c5c7','00000000-0000-0000-0000-00000000a5fa','00000000-0000-0000-0000-00000000acda','00000000-0000-0000-0000-00000000da11','o-ks',0) ->> 'error', 'permission_denied', 'kitchen_staff may NOT open a shift');
select is(app.open_shift('00000000-0000-0000-0000-00000000c5c6','00000000-0000-0000-0000-00000000a5fb','00000000-0000-0000-0000-00000000acdb','00000000-0000-0000-0000-00000000da11','o-ac',0) ->> 'error', 'permission_denied', 'accountant may NOT open a shift');

-- ===== close_shift gates ===================================================== 9-12
select is(app.close_shift('00000000-0000-0000-0000-00000000c5c2','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','c-c2',0,null) ->> 'error', 'permission_denied', 'a cashier may NOT close ANOTHER cashier''s shift');
select is(app.close_shift('00000000-0000-0000-0000-00000000c5c6','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','c-ac',0,null) ->> 'error', 'permission_denied', 'an accountant may NOT close a shift');
select is(app.close_shift('00000000-0000-0000-0000-00000000c5c7','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','c-ks',0,null) ->> 'error', 'permission_denied', 'kitchen_staff may NOT close a shift');
select is((app.close_shift('00000000-0000-0000-0000-00000000c5c3','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','c-mgr',0,null) ->> 'ok')::boolean, true, 'a manager may close a cashier''s shift on behalf');

-- ===== reconcile_shift gates (sh-c1 is now closed) =========================== 13-16
select is(app.reconcile_shift('00000000-0000-0000-0000-00000000c5c1','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','r-c1',null) ->> 'error', 'permission_denied', 'a cashier may NOT reconcile (separation of duties)');
select is(app.reconcile_shift('00000000-0000-0000-0000-00000000c5c6','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','r-ac',null) ->> 'error', 'permission_denied', 'an accountant may NOT reconcile (D-028)');
select is(app.reconcile_shift('00000000-0000-0000-0000-00000000c5c7','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','r-ks',null) ->> 'error', 'permission_denied', 'kitchen_staff may NOT reconcile');
select is((app.reconcile_shift('00000000-0000-0000-0000-00000000c5c3','00000000-0000-0000-0000-00000000a5f4','00000000-0000-0000-0000-00000000da11','r-mgr',null) ->> 'status'), 'reconciled', 'a manager may reconcile the cashier-closed shift');

-- ===== cross-scope: a b1 cashier cannot act on a b2 shift ==================== 17
select app.open_shift('00000000-0000-0000-0000-00000000c5b2','00000000-0000-0000-0000-00000000a5fc','00000000-0000-0000-0000-00000000acdc','00000000-0000-0000-0000-00000000db22','o-b2',0);
select throws_ok($$ select app.close_shift('00000000-0000-0000-0000-00000000c5c1','00000000-0000-0000-0000-00000000a5fc','00000000-0000-0000-0000-00000000da11','c-x',0,null) $$, '42501', NULL, 'a cashier cannot close a shift in another branch (cross-scope rejected)');

-- ===== denied attempts are audited =========================================== 18-20
select is((select count(*) from audit_events where action='shift.open_denied')::int,      2, 'two shift.open_denied audit rows (kitchen + accountant)');
select is((select count(*) from audit_events where action='shift.close_denied')::int,     3, 'three shift.close_denied audit rows (cashier2 + accountant + kitchen)');
select is((select count(*) from audit_events where action='shift.reconcile_denied')::int, 3, 'three shift.reconcile_denied audit rows (cashier + accountant + kitchen)');

select * from finish();
rollback;
